import Starling from '@ies/starling_client_core';
import { Options } from '@ies/starling_client_core/lib/options';
import { store } from './store';
import { request } from './request';

type WithOptional<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;
export type WebOptions = WithOptional<Options, 'store' | 'request'>;

class StarlingWebBase extends Starling {
  constructor(options: WebOptions) {
    if (!options.store) options.store = store;
    if (!options.request) options.request = request;
    super(options as Options);
  }
}

export default StarlingWebBase;
